import{_ as t,o as i,c as h,a0 as a}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Vùng miền","description":"","frontmatter":{"title":"Vùng miền"},"headers":[],"relativePath":"regional.md","filePath":"regional.md"}'),o={name:"regional.md"};function l(r,n,g,u,e,s){return i(),h("div",null,[...n[0]||(n[0]=[a('<h1 id="vung-mien" tabindex="-1">Vùng miền <a class="header-anchor" href="#vung-mien" aria-label="Permalink to &quot;Vùng miền&quot;">​</a></h1><p>ABNERP hỗ trợ đa dạng các thiết lập vùng miền (Regional) để đáp ứng yêu cầu pháp lý, thuế và vận hành đặc thù của từng quốc gia. Mỗi thiết lập vùng miền bao gồm cấu hình về thuế, báo cáo tài chính, ngôn ngữ, định dạng ngày tháng và quy định kế toán riêng.</p><h2 id="viet-nam" tabindex="-1">Việt Nam <a class="header-anchor" href="#viet-nam" aria-label="Permalink to &quot;Việt Nam&quot;">​</a></h2><p>Thiết lập dành riêng cho Việt Nam bao gồm:</p><ul><li><strong>Thuế GTGT (VAT)</strong>: hệ thống thuế giá trị gia tăng với các mức thuế suất 0%, 5%, 8% và 10%</li><li><strong>Hóa đơn điện tử</strong>: hỗ trợ định dạng hóa đơn theo quy định của Tổng cục Thuế</li><li><strong>Báo cáo thuế</strong>: tờ khai thuế GTGT, báo cáo tình hình sử dụng hóa đơn</li><li><strong>Sổ kế toán</strong>: các sổ sách theo chế độ kế toán doanh nghiệp Việt Nam</li><li><strong>Báo cáo tài chính</strong>: bảng cân đối kế toán, báo cáo kết quả kinh doanh, báo cáo lưu chuyển tiền tệ</li></ul><h2 id="an-đo" tabindex="-1">Ấn Độ <a class="header-anchor" href="#an-đo" aria-label="Permalink to &quot;Ấn Độ&quot;">​</a></h2><p>Thiết lập cho thị trường Ấn Độ bao gồm:</p><ul><li><strong>GST (Goods and Services Tax)</strong>: quản lý đầy đủ GST đầu vào và đầu ra</li><li><strong>HSN/SAC</strong>: mã hóa thống nhất cho hàng hóa và dịch vụ</li><li><strong>e-Way Bill</strong>: tích hợp tạo và quản lý vận đơn điện tử</li><li><strong>Báo cáo GST</strong>: GSTR-1, GSTR-2, GSTR-3B và các báo cáo thuế khác</li><li><strong>Pan &amp; TAN</strong>: quản lý mã số thuế của đối tác và doanh nghiệp</li></ul><h2 id="uae" tabindex="-1">UAE <a class="header-anchor" href="#uae" aria-label="Permalink to &quot;UAE&quot;">​</a></h2><p>Thiết lập cho Các Tiểu vương quốc Ả Rập Thống nhất:</p><ul><li><strong>VAT 5%</strong>: thuế giá trị gia tăng theo quy định UAE</li><li><strong>Báo cáo VAT</strong>: tờ khai thuế VAT định kỳ</li><li><strong>Định dạng tài liệu</strong>: hóa đơn và chứng từ theo chuẩn địa phương</li><li><strong>Tiền tệ</strong>: UAE Dirham (AED)</li></ul><h2 id="a-rap-saudi" tabindex="-1">Ả Rập Saudi <a class="header-anchor" href="#a-rap-saudi" aria-label="Permalink to &quot;Ả Rập Saudi&quot;">​</a></h2><p>Thiết lập cho Ả Rập Saudi bao gồm:</p><ul><li><strong>VAT 15%</strong>: thuế giá trị gia tăng theo quy định</li><li><strong>Zakat &amp; CIT</strong>: hỗ trợ tính toán thuế thu nhập doanh nghiệp</li><li><strong>E-invoicing</strong>: tích hợp hệ thống hóa đơn điện tử ZATCA</li><li><strong>Tiền tệ</strong>: Saudi Riyal (SAR)</li></ul><h2 id="my" tabindex="-1">Mỹ <a class="header-anchor" href="#my" aria-label="Permalink to &quot;Mỹ&quot;">​</a></h2><p>Thiết lập cho Hoa Kỳ:</p><ul><li><strong>Sales Tax</strong>: thuế bán hàng theo từng tiểu bang</li><li><strong>1099</strong>: hỗ trợ khai báo thuế cho nhà thầu độc lập</li><li><strong>Định dạng tài liệu</strong>: theo chuẩn GAAP</li><li><strong>Tiền tệ</strong>: US Dollar (USD)</li></ul><h2 id="y" tabindex="-1">Ý <a class="header-anchor" href="#y" aria-label="Permalink to &quot;Ý&quot;">​</a></h2><p>Thiết lập cho Ý:</p><ul><li><strong>VAT</strong>: thuế GTGT với nhiều mức thuế suất (4%, 5%, 10%, 22%)</li><li><strong>E-invoicing</strong>: tích hợp hệ thống hóa đơn điện tử giao diện SdI (Sistema di Interscambio)</li><li><strong>Báo cáo tài chính</strong>: theo chuẩn kế toán Ý và quy định của Cục Thuế</li></ul><h2 id="phap" tabindex="-1">Pháp <a class="header-anchor" href="#phap" aria-label="Permalink to &quot;Pháp&quot;">​</a></h2><p>Thiết lập cho Pháp:</p><ul><li><strong>VAT</strong>: thuế GTGT theo biểu thuế Pháp</li><li><strong>Báo cáo thuế</strong>: tờ khai TVA (Taxe sur la Valeur Ajoutée)</li><li><strong>Định dạng số và ngày</strong>: theo chuẩn Pháp</li><li><strong>Tiền tệ</strong>: Euro (EUR)</li></ul><h3 id="chuyen-đoi-vung-mien" tabindex="-1">Chuyển đổi vùng miền <a class="header-anchor" href="#chuyen-đoi-vung-mien" aria-label="Permalink to &quot;Chuyển đổi vùng miền&quot;">​</a></h3><p>Người dùng có thể dễ dàng chuyển đổi giữa các thiết lập vùng miền thông qua giao diện cài đặt hệ thống. Mỗi vùng miền tự động cập nhật các tham số thuế, kế toán và báo cáo tương ứng, đảm bảo tuân thủ quy định địa phương và giảm thiểu sai sót trong quá trình vận hành.</p>',25)])])}const d=t(o,[["render",l]]);export{p as __pageData,d as default};
